contract_template.code:
// aq_schema/lib/{service}/api_contract/{service}_api_contract.dart
class VaultApiContract implements IAqApiContract {
  const VaultApiContract();

  @override
  String get apiVersion => 'v1';

  @override
  String get basePath => '/vault';

  @override
  Map<String, RouteSpec> get routes => {
    'handshake': const RouteSpec(
      path: '/handshake',
      method: 'POST',
      description: 'Connection handshake',
      requiresAuth: false,
    ),
    'rpc': const RouteSpec(
      path: '/rpc',
      method: 'POST',
      description: 'Repository operations',
      requiresAuth: true,
    ),
    'health': const RouteSpec(
      path: '/health',
      method: 'GET',
      description: 'Health check',
      requiresAuth: false,
    ),
  };

  // Константы маршрутов — не хардкодить строки снаружи
  static const String routeHandshake = 'handshake';
  static const String routeRpc = 'rpc';
  static const String routeHealth = 'health';
}

builder_template.code:
// aq_schema/lib/{service}/api_contract/{service}_api_route_builder.dart
class VaultApiRouteBuilder implements IAqApiRouteBuilder {
  @override final VaultApiContract contract;
  @override final String baseUrl;

  const VaultApiRouteBuilder(this.contract, this.baseUrl);

  String handshake() => contract.buildUrl(baseUrl, VaultApiContract.routeHandshake);
  String rpc()       => contract.buildUrl(baseUrl, VaultApiContract.routeRpc);
  String health()    => contract.buildUrl(baseUrl, VaultApiContract.routeHealth);
}

client_usage.correct:
// ✅ ПРАВИЛЬНО
import 'package:aq_schema/data.dart';

class RemoteVaultStorage {
  final VaultApiContract _contract = const VaultApiContract();
  late final VaultApiRouteBuilder _routes;

  RemoteVaultStorage(String baseUrl) {
    _routes = _contract.createRouteBuilder(baseUrl);
  }

  Future<void> handshake() async {
    final url = _routes.handshake(); // ✅ Типобезопасно
    await http.post(Uri.parse(url), ...);
  }
}

client_usage.incorrect:
// ❌ ЗАПРЕЩЕНО — хардкод маршрута
Future<void> handshake() async {
  final url = '$baseUrl/vault/handshake'; // ❌ Хардкод
  await http.post(Uri.parse(url), ...);
}

server_usage.correct:
// ✅ ПРАВИЛЬНО
import 'package:aq_schema/data.dart';

void main() async {
  final contract = VaultApiContract();

  final router = Router()
    ..post(contract.getFullRoute('handshake'), _handleHandshake)
    ..post(contract.getFullRoute('rpc'), _handleRpc)
    ..get(contract.getFullRoute('health'), _handleHealth);
}

server_usage.incorrect:
// ❌ ЗАПРЕЩЕНО — хардкод маршрута на сервере
final router = Router()
  ..post('/handshake', _handleHandshake)  // ❌ Не совпадёт с клиентом
  ..post('/rpc', _handleRpc);

